import{c as h,S as t,j as i,m as a}from"./chunks/framework.8aa1YH_s.js";const k=JSON.parse('{"title":"Đăng ký & Đăng nhập","description":"","frontmatter":{},"headers":[],"relativePath":"hoc-vien/dang-ky-dang-nhap.md","filePath":"hoc-vien/dang-ky-dang-nhap.md","lastUpdated":0}'),o={name:"hoc-vien/dang-ky-dang-nhap.md"};function l(g,n,r,s,c,e){return t(),i("div",null,[...n[0]||(n[0]=[a('<h1 id="đang-ky-đang-nhap" tabindex="-1">Đăng ký &amp; Đăng nhập <a class="header-anchor" href="#đang-ky-đang-nhap" aria-label="Permalink to “Đăng ký &amp; Đăng nhập”">​</a></h1><h2 id="đang-ky-tai-khoan-moi" tabindex="-1">Đăng ký tài khoản mới <a class="header-anchor" href="#đang-ky-tai-khoan-moi" aria-label="Permalink to “Đăng ký tài khoản mới”">​</a></h2><ol><li>Mở trang chủ LamSơn Edutech.</li><li>Bấm <strong>Đăng ký</strong> ở góc phải trên (hoặc vào <code>https://lamsonedutech.vn/auth/hocvien</code>).</li><li>Điền: <ul><li><strong>Họ và tên</strong> (chính xác - sẽ in trên báo cáo, chứng nhận nếu có).</li><li><strong>Số điện thoại</strong> (dùng để đăng nhập + nhận OTP).</li><li><strong>Email</strong> (dùng để khôi phục mật khẩu, nhận biên lai).</li><li><strong>Mật khẩu</strong> (≥ 6 ký tự, nên có chữ + số + ký tự đặc biệt).</li><li><strong>Xác nhận mật khẩu</strong>.</li><li>(Tùy chọn) <strong>Khối lớp</strong> (10/11/12), <strong>Tỉnh / Thành phố</strong>.</li></ul></li><li>Tick <strong>Tôi đồng ý điều khoản sử dụng</strong>.</li><li>Bấm <strong>Đăng ký</strong>.</li><li><strong>Nhập mã OTP</strong> được gửi qua SMS / email để xác thực.</li><li>Hoàn tất - bạn được tự đăng nhập vào hệ thống.</li></ol><h2 id="đang-nhap" tabindex="-1">Đăng nhập <a class="header-anchor" href="#đang-nhap" aria-label="Permalink to “Đăng nhập”">​</a></h2><ol><li>Vào <code>https://lamsonedutech.vn/auth/hocvien</code>.</li><li>Nhập <strong>Số điện thoại hoặc Email</strong> + <strong>Mật khẩu</strong>.</li><li>(Tùy chọn) Tick <strong>Ghi nhớ đăng nhập</strong> để không phải nhập lại trên cùng trình duyệt.</li><li>Bấm <strong>Đăng nhập</strong>.</li></ol><h2 id="đang-nhap-bang-mang-xa-hoi-neu-co" tabindex="-1">Đăng nhập bằng mạng xã hội (nếu có) <a class="header-anchor" href="#đang-nhap-bang-mang-xa-hoi-neu-co" aria-label="Permalink to “Đăng nhập bằng mạng xã hội (nếu có)”">​</a></h2><p>Một số phiên bản hệ thống hỗ trợ:</p><ul><li><strong>Đăng nhập bằng Google</strong></li><li><strong>Đăng nhập bằng Facebook</strong></li><li><strong>Đăng nhập bằng Zalo</strong></li></ul><p>Bấm icon tương ứng → cấp quyền → hệ thống tự tạo tài khoản (nếu chưa có) và đăng nhập.</p><blockquote><p>⚠️ Khi đăng nhập lần đầu qua mạng xã hội, bạn vẫn cần <strong>bổ sung số điện thoại</strong> để có thể thanh toán và nhận thông báo.</p></blockquote><h2 id="quen-mat-khau" tabindex="-1">Quên mật khẩu <a class="header-anchor" href="#quen-mat-khau" aria-label="Permalink to “Quên mật khẩu”">​</a></h2><ol><li>Tại trang đăng nhập, bấm <strong>Quên mật khẩu?</strong>.</li><li>Nhập <strong>Số điện thoại / Email</strong> đã đăng ký.</li><li>Nhận <strong>OTP</strong> qua SMS hoặc email.</li><li>Nhập OTP → màn hình đặt mật khẩu mới.</li><li>Đặt mật khẩu mới, xác nhận → đăng nhập với mật khẩu mới.</li></ol><blockquote><p>💡 Nếu không nhận được OTP, kiểm tra hộp thư rác hoặc liên hệ hotline trung tâm.</p></blockquote><h2 id="đang-xuat" tabindex="-1">Đăng xuất <a class="header-anchor" href="#đang-xuat" aria-label="Permalink to “Đăng xuất”">​</a></h2><ul><li>Bấm vào <strong>avatar / tên của bạn</strong> ở góc phải.</li><li>Chọn <strong>Đăng xuất</strong>.</li><li>Mọi tab đang mở của hệ thống sẽ cần đăng nhập lại.</li></ul><h2 id="đoi-mat-khau-đinh-ky" tabindex="-1">Đổi mật khẩu định kỳ <a class="header-anchor" href="#đoi-mat-khau-đinh-ky" aria-label="Permalink to “Đổi mật khẩu định kỳ”">​</a></h2><ul><li>Vào <code>https://lamsonedutech.vn/luyen-tap/nguoi-dung/profile</code> → tab <strong>Đổi mật khẩu</strong>.</li><li>Nhập mật khẩu hiện tại + mật khẩu mới + xác nhận → <strong>Lưu</strong>.</li></ul><h2 id="an-toan-tai-khoan" tabindex="-1">An toàn tài khoản <a class="header-anchor" href="#an-toan-tai-khoan" aria-label="Permalink to “An toàn tài khoản”">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Không chia sẻ tài khoản</p><ul><li>Mỗi tài khoản gắn với 1 người. Chia sẻ có thể bị <strong>khóa vĩnh viễn</strong> + mất khóa đã mua.</li><li>Khóa học bạn mua chỉ dùng cho bạn.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Mật khẩu mạnh</p><ul><li>≥ 8 ký tự</li><li>Có chữ in hoa, chữ thường, số</li><li>Không dùng mật khẩu giống các tài khoản khác (Facebook, email...)</li></ul></div><h2 id="su-co-thuong-gap" tabindex="-1">Sự cố thường gặp <a class="header-anchor" href="#su-co-thuong-gap" aria-label="Permalink to “Sự cố thường gặp”">​</a></h2><p><strong>Không nhận được OTP đăng ký?</strong></p><ul><li>Kiểm tra số đã nhập đúng chưa.</li><li>Đợi 60s rồi bấm <strong>Gửi lại</strong>.</li><li>Kiểm tra hộp thư rác (email).</li><li>Nhà mạng đôi khi chặn SMS - thử dùng số khác hoặc email.</li></ul><p><strong>&quot;Tài khoản đã tồn tại&quot; khi đăng ký?</strong></p><ul><li>Số điện thoại / email này đã có người dùng. Thử <strong>Quên mật khẩu</strong> để khôi phục.</li></ul><p><strong>Đăng nhập sai mật khẩu quá nhiều lần?</strong></p><ul><li>Tài khoản bị khóa tạm thời ~15 phút. Đợi rồi thử lại, hoặc dùng <strong>Quên mật khẩu</strong>.</li></ul><p><strong>Bị &quot;đăng xuất ngoài ý muốn&quot; trong khi đang học?</strong></p><ul><li>Có thể bạn đăng nhập trên thiết bị khác. Hệ thống thường chỉ cho phép 1-2 phiên đồng thời.</li><li>Đăng nhập lại để tiếp tục.</li></ul>',29)])])}const p=h(o,[["render",l]]);export{k as __pageData,p as default};
